// Espera receber { session_id, from, text } como entrada deste sub-workflow
const msg = $json || {};

const sessionId = String(msg.session_id || '').trim();
const from      = String(msg.from || '').replace(/\D/g,'');
const text      = String(msg.text || '').trim();

// helpers
const toNumberOrNull = (s) => (/^\d+$/.test(s) ? Number(s) : null);
const yesNo = (s) => {
  const t = s.toLowerCase();
  if (/(sim|s|yes|y)/.test(t))  return true;
  if (/(não|nao|n|no)/.test(t)) return false;
  return null;
};

return [{
  json: {
    session_id: sessionId,
    from,
    text,
    parsed: { nps: toNumberOrNull(text), bool: yesNo(text) }
  }
}];

const rows = $input.all();
let step = 'q1';
if (rows.length && rows[0].json && rows[0].json.coleta_step) {
  step = rows[0].json.coleta_step;
}
const base = $item(0).$node['Parse Response'].json;
return [{ json: { ...base, coleta_step: step } }];

const base = $item(0).$node['Parse Response'].json;
const n = base.parsed?.nps;
if (n === null || n === undefined || n < 0 || n > 10) {
  return [{ json: { error: 'invalid_nps', session_id: base.session_id, from: base.from } }];
}
return [{ json: { nps: n, session_id: base.session_id, from: base.from } }];

const base = $item(0).$node['Parse Response'].json;
const yn = base.parsed?.bool;
return [{ json: { session_id: base.session_id, from: base.from, intent: (yn === true ? true : (yn === false ? false : null)) } }];

